(async function(Scratch) {
    const variables = {};
    const blocks = [];
    const menus = {};


    if (!Scratch.extensions.unsandboxed) {
        alert("This extension needs to be unsandboxed to run!")
        return
    }

    function doSound(ab, cd, runtime) {
        const audioEngine = runtime.audioEngine;

        const fetchAsArrayBufferWithTimeout = (url) =>
            new Promise((resolve, reject) => {
                const xhr = new XMLHttpRequest();
                let timeout = setTimeout(() => {
                    xhr.abort();
                    reject(new Error("Timed out"));
                }, 5000);
                xhr.onload = () => {
                    clearTimeout(timeout);
                    if (xhr.status === 200) {
                        resolve(xhr.response);
                    } else {
                        reject(new Error(`HTTP error ${xhr.status} while fetching ${url}`));
                    }
                };
                xhr.onerror = () => {
                    clearTimeout(timeout);
                    reject(new Error(`Failed to request ${url}`));
                };
                xhr.responseType = "arraybuffer";
                xhr.open("GET", url);
                xhr.send();
            });

        const soundPlayerCache = new Map();

        const decodeSoundPlayer = async (url) => {
            const cached = soundPlayerCache.get(url);
            if (cached) {
                if (cached.sound) {
                    return cached.sound;
                }
                throw cached.error;
            }

            try {
                const arrayBuffer = await fetchAsArrayBufferWithTimeout(url);
                const soundPlayer = await audioEngine.decodeSoundPlayer({
                    data: {
                        buffer: arrayBuffer,
                    },
                });
                soundPlayerCache.set(url, {
                    sound: soundPlayer,
                    error: null,
                });
                return soundPlayer;
            } catch (e) {
                soundPlayerCache.set(url, {
                    sound: null,
                    error: e,
                });
                throw e;
            }
        };

        const playWithAudioEngine = async (url, target) => {
            const soundBank = target.sprite.soundBank;

            let soundPlayer;
            try {
                const originalSoundPlayer = await decodeSoundPlayer(url);
                soundPlayer = originalSoundPlayer.take();
            } catch (e) {
                console.warn(
                    "Could not fetch audio; falling back to primitive approach",
                    e
                );
                return false;
            }

            soundBank.addSoundPlayer(soundPlayer);
            await soundBank.playSound(target, soundPlayer.id);

            delete soundBank.soundPlayers[soundPlayer.id];
            soundBank.playerTargets.delete(soundPlayer.id);
            soundBank.soundEffects.delete(soundPlayer.id);

            return true;
        };

        const playWithAudioElement = (url, target) =>
            new Promise((resolve, reject) => {
                const mediaElement = new Audio(url);

                mediaElement.volume = target.volume / 100;

                mediaElement.onended = () => {
                    resolve();
                };
                mediaElement
                    .play()
                    .then(() => {
                        // Wait for onended
                    })
                    .catch((err) => {
                        reject(err);
                    });
            });

        const playSound = async (url, target) => {
            try {
                if (!(await Scratch.canFetch(url))) {
                    throw new Error(`Permission to fetch ${url} denied`);
                }

                const success = await playWithAudioEngine(url, target);
                if (!success) {
                    return await playWithAudioElement(url, target);
                }
            } catch (e) {
                console.warn(`All attempts to play ${url} failed`, e);
            }
        };

        playSound(ab, cd)
    }
    class Extension {
        getInfo() {
            return {
                "blockIconURI": "data:image/png;base64,",
                "id": "SimpleJs",
                "name": "Simple JavaScript",
                "docsURI": "https://docs.google.com/document/d/11yfULU2bhgScyd197s3vmxdR-lVyaQvnoOJKtGoBE9U/edit?usp=drivesdk",
                "color1": "#0071c0",
                "color2": "#004def",
                "tbShow": true,
                "blocks": blocks,
                "menus": menus
            }
        }
    }
    blocks.push({
        opcode: "Alert",
        blockType: Scratch.BlockType.COMMAND,
        text: "Alert [alertText]",
        arguments: {
            "alertText": {
                type: Scratch.ArgumentType.STRING,
                defaultValue: 'Hy',
            },
        },
        disableMonitor: true,
        isEdgeActivated: false
    });
    Extension.prototype["Alert"] = async (args, util) => {
        alert(args["alertText"])
    };

    blocks.push({
        opcode: "Prompt",
        blockType: Scratch.BlockType.REPORTER,
        text: "Prompt [promptText]",
        arguments: {
            "promptText": {
                type: Scratch.ArgumentType.STRING,
                defaultValue: 'What is your name ?',
            },
        },
        disableMonitor: true,
        isEdgeActivated: false
    });
    Extension.prototype["Prompt"] = async (args, util) => {
        return prompt(args["promptText"])
    };

    blocks.push({
        opcode: "Confirm",
        blockType: Scratch.BlockType.BOOLEAN,
        text: "Confirm [confirmText]",
        arguments: {
            "confirmText": {
                type: Scratch.ArgumentType.STRING,
                defaultValue: 'Is this cool 😎 ?',
            },
        },
        disableMonitor: true,
        isEdgeActivated: false
    });
    Extension.prototype["Confirm"] = async (args, util) => {
        if (Boolean(confirm(args["confirmText"]))) {
            return true

        } else {
            return false

        };
    };

    blocks.push({
        opcode: "LetAndSet",
        blockType: Scratch.BlockType.COMMAND,
        text: "Let/set [set] to [setTo]",
        arguments: {
            "set": {
                type: Scratch.ArgumentType.STRING,
                defaultValue: 'Score',
            },
            "setTo": {
                type: Scratch.ArgumentType.STRING,
                defaultValue: '1000',
            },
        },
        disableMonitor: true,
        isEdgeActivated: false
    });
    Extension.prototype["LetAndSet"] = async (args, util) => {
        variables[args["set"]] = args["setTo"]
    };

    blocks.push({
        opcode: "DeleteVar",
        blockType: Scratch.BlockType.COMMAND,
        text: "Delete [DeleteVar]",
        arguments: {
            "DeleteVar": {
                type: Scratch.ArgumentType.STRING,
                defaultValue: 'Score',
            },
        },
        disableMonitor: true,
        isEdgeActivated: false
    });
    Extension.prototype["DeleteVar"] = async (args, util) => {
        variables[args["DeleteVar"]] = ""
    };

    blocks.push({
        opcode: "GetVariable",
        blockType: Scratch.BlockType.REPORTER,
        text: "Get [get]",
        arguments: {
            "get": {
                type: Scratch.ArgumentType.STRING,
                defaultValue: 'Score',
            },
        },
        disableMonitor: true,
        isEdgeActivated: false
    });
    Extension.prototype["GetVariable"] = async (args, util) => {
        return variables[args["get"]]
    };

    blocks.push({
        opcode: "Pi",
        blockType: Scratch.BlockType.REPORTER,
        text: "Pi",
        arguments: {},
        disableMonitor: true,
        isEdgeActivated: false
    });
    Extension.prototype["Pi"] = async (args, util) => {
        return (22 / 7)
    };

    blocks.push({
        opcode: "LocalSet",
        blockType: Scratch.BlockType.COMMAND,
        text: "Let/set [SetLocal] to [SetToLocal] in storage",
        arguments: {
            "SetLocal": {
                type: Scratch.ArgumentType.STRING,
                defaultValue: 'Score',
            },
            "SetToLocal": {
                type: Scratch.ArgumentType.STRING,
                defaultValue: '1000',
            },
        },
        disableMonitor: true,
        isEdgeActivated: false
    });
    Extension.prototype["LocalSet"] = async (args, util) => {
        localStorage.setItem(args["SetLocal"], args["SetToLocal"])
    };

    blocks.push({
        opcode: "Delete",
        blockType: Scratch.BlockType.COMMAND,
        text: "Delete [Delete] from storage",
        arguments: {
            "Delete": {
                type: Scratch.ArgumentType.STRING,
                defaultValue: 'Score',
            },
        },
        disableMonitor: true,
        isEdgeActivated: false
    });
    Extension.prototype["Delete"] = async (args, util) => {
        localStorage.setItem(args["Delete"], 'null')
    };

    blocks.push({
        opcode: "GetLocal",
        blockType: Scratch.BlockType.REPORTER,
        text: "Get [GetLocal] from storage",
        arguments: {
            "GetLocal": {
                type: Scratch.ArgumentType.STRING,
                defaultValue: 'Score',
            },
        },
        disableMonitor: true,
        isEdgeActivated: false
    });
    Extension.prototype["GetLocal"] = async (args, util) => {
        if (Boolean((localStorage.getItem(args["GetLocal"]) == 'null'))) {
            return ''

        } else {
            return localStorage.getItem(args["GetLocal"])

        };
    };

    Scratch.extensions.register(new Extension());
})(Scratch);
